// src/components/InteractionForm.js
import React from "react";
import { useSelector } from "react-redux";

function InteractionForm() {
  const form = useSelector((state) => state.form);

  // Emoji mapping for sentiment
  const sentimentEmoji = {
    positive: "😊",
    neutral: "😐",
    negative: "😞",
  };

  return (
    <div>
      <h2 style={{ color: "#2a2a72" }}>Log HCP Interaction</h2>

      <input
        placeholder="HCP Name"
        value={form.hcp_name || ""}
        readOnly
      />

      <input
        placeholder="Interaction Type"
        value={form.interaction_type || ""}
        readOnly
      />

      <input
        placeholder="Date"
        value={form.date || ""}
        readOnly
      />

      <input
        placeholder="Time"
        value={form.time || ""}
        readOnly
      />

      <textarea
        placeholder="Topics Discussed"
        value={form.topics || ""}
        readOnly
      />

      <textarea
        placeholder="Outcomes"
        value={form.outcomes || ""}
        readOnly
      />

      <textarea
        placeholder="Follow Up"
        value={form.followup || ""}
        readOnly
      />

      {form.sentiment && (
        <div>
          <strong>Sentiment: </strong>
          <span>{sentimentEmoji[form.sentiment]} {form.sentiment}</span>
        </div>
      )}

      {/* ----- Render tools outputs ----- */}
      {form.tools && Object.keys(form.tools).length > 0 && (
        <div style={{ marginTop: "20px" }}>
          <h3 style={{ color: "#2a2a72" }}>Tools Outputs</h3>
          {Object.entries(form.tools).map(([toolName, value], idx) => (
            <div
              key={idx}
              style={{
                border: "1px solid #ccc",
                padding: "10px",
                marginBottom: "8px",
                borderRadius: "8px",
                backgroundColor: "#f0f4ff",
              }}
            >
              <strong>{toolName}:</strong>
              <pre style={{ whiteSpace: "pre-wrap", marginTop: "5px" }}>
                {JSON.stringify(value, null, 2)}
              </pre>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default InteractionForm;
